const crypto = require('crypto');

const token = `${$input.first().json.token}`;
const secret = `${$input.first().json.secret}`;
const t = Date.now();
const nonce = "123456789";
const data = token + t + nonce;
const sign = crypto
    .createHmac('sha256', secret)
    .update(data)
    .digest('base64');
return {
  'Authorization': token,
  'sign': sign,
  'nonce': nonce,
  't': t
};
